346	pub fn rbtdri_read_burv_fact(
347	    result: &rbtdri_InvokeResult,
348	    fact_name: &str,
349	) -> Result<String, String> {
350	    let path = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR).join(fact_name);
351	    let content = std::fs::read_to_string(&path)
352	        .map_err(|e| format!("rbtdri: cannot read fact '{}' from {}: {}", fact_name, path.display(), e))?;
353	    let trimmed = content.trim().to_string();
354	    if trimmed.is_empty() {
355	        return Err(format!("rbtdri: fact '{}' is empty in {}", fact_name, path.display()));
356	    }
357	    Ok(trimmed)
358	}
