360	/// Enumerate multi-fact files in a tabtarget's BURV output directory.
361	/// Multi-facts follow the convention `<root>.<ext>` written by buf_write_fact_multi;
362	/// returns the sorted list of roots whose files have the requested extension.
363	/// Returns an empty Vec if no matching files exist.
364	pub fn rbtdri_read_burv_facts_multi(
365	    result: &rbtdri_InvokeResult,
366	    extension: &str,
367	) -> Result<Vec<String>, String> {
368	    let dir = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
369	    let entries = std::fs::read_dir(&dir).map_err(|e| {
370	        format!(
371	            "rbtdri: cannot enumerate fact dir {}: {}",
372	            dir.display(),
373	            e
374	        )
375	    })?;
376	    let suffix = format!(".{}", extension);
377	    let mut roots: Vec<String> = entries
378	        .filter_map(|entry| entry.ok())
379	        .filter_map(|entry| entry.file_name().into_string().ok())
380	        .filter_map(|name| name.strip_suffix(&suffix).map(str::to_string))
381	        .collect();
382	    roots.sort();
383	    Ok(roots)
384	}
