386	// ── Ifrit verdict parsing ────────────────────────────────────
387	
388	/// Ifrit verdict wire protocol: ifrit prints exactly one line matching
389	/// `IFRIT_VERDICT: PASS` or `IFRIT_VERDICT: FAIL <detail>` to stdout.
390	/// Missing verdict line is always a failure — no silent pass-through.
391	pub fn rbtdri_parse_ifrit_verdict(stdout: &str, exit_code: i32) -> rbtdre_Verdict {
392	    for line in stdout.lines() {
393	        let trimmed = line.trim();
394	        if let Some(rest) = trimmed.strip_prefix("IFRIT_VERDICT:") {
395	            let rest = rest.trim();
396	            if rest.starts_with("PASS") {
397	                return rbtdre_Verdict::Pass;
398	            }
399	            if let Some(detail) = rest.strip_prefix("FAIL") {
400	                let detail = detail.trim();
401	                if detail.is_empty() {
402	                    return rbtdre_Verdict::Fail("ifrit reported failure".to_string());
403	                }
404	                return rbtdre_Verdict::Fail(detail.to_string());
405	            }

